check-embeddedfile-exists-before-delete.code:
const string attachmentName = "invoice.xml";
bool attachmentFound = document.EmbeddedFiles.Any(f => string.Equals(f.Name, attachmentName, StringComparison.OrdinalIgnoreCase));
if (attachmentFound)
{
    document.EmbeddedFiles.Delete(attachmentName);
    Console.WriteLine($"Attachment '{attachmentName}' removed.");
}
else
{
    Console.WriteLine($"Attachment '{attachmentName}' not found – no changes made.");
}

