create-document-if-input-missing.code:
string inputPath = "input.pdf";
Document doc;
if (!File.Exists(inputPath))
{
    doc = new Document();
    doc.Pages.Add(); // ensure at least one page
    doc.Save(inputPath);
}
else
{
    doc = new Document(inputPath);
}

process-all-operators-no-limit.code:
OperatorCollection ops = page.Contents;
var updated = new List<Operator>();
foreach (Operator op in ops)
{
    if (op is ShowText st && !string.IsNullOrEmpty(st.Text) && st.Text.Contains("Hello"))
    {
        var repl = new ShowText(st.Text.Replace("Hello", "Hi")) { Index = st.Index };
        updated.Add(repl);
    }
    else
    {
        updated.Add(op);
    }
}
ops.Clear();
foreach (var o in updated) ops.Add(o);

