validate-file-existence-before-xmlloadop.code:
string baseDir = AppDomain.CurrentDomain.BaseDirectory;
string xmlPath = Path.Combine(baseDir, "input.xml");
string xslPath = Path.Combine(baseDir, "transform.xsl");
if (!File.Exists(xmlPath) || !File.Exists(xslPath))
    return; // handle missing files
XmlLoadOptions loadOptions = new XmlLoadOptions(xslPath);
using (Document pdf = new Document(xmlPath, loadOptions))
{
    pdf.Save("output.pdf");
}

